import React, { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { resolveBrandName, formatRent, safeFloat } from '../../../utils/formatters';

const UpcomingEscalations = ({ leases = [], loading }) => {
  const navigate = useNavigate();

  const handleUnitClick = (unitId) => {
    if (unitId) navigate(`/admin/view-unit/${unitId}`);
  };

  const handleLeaseClick = (leaseId) => {
    navigate(`/admin/view-lease/${leaseId}`);
  };

  // Color coding based on days until escalation
  // Red: <= 30 days (Critical), Blue: 30-90 days (Secure), Green: > 90 days (Active)
  const getEscalationColor = (days) => {
    if (days <= 30) return { bg: '#fee2e2', text: '#991b1b', status: 'Critical' };
    if (days <= 90) return { bg: '#dbeafe', text: '#1d4ed8', status: 'Secure' };
    return { bg: '#dcfce7', text: '#166534', status: 'Active' };
  };

  // Calculate escalations from lease data using the escalations[] array returned by the backend
  const escalationData = useMemo(() => {
    if (!leases || leases.length === 0) return [];

    const now = new Date();
    const escalations = [];

    // Filter active leases first
    const activeLeases = leases.filter(lease => {
      const status = (lease.status || '').toLowerCase().trim();
      return status === 'active' || status === 'approved' || status === 'executed' || status === 'registered' || status === 'occupied';
    });

    activeLeases.forEach(lease => {
      // Use the escalations array embedded by the backend (from lease_escalations table)
      const leaseEscalations = Array.isArray(lease.escalations) ? lease.escalations : [];

      // Resolve unit number from all possible field paths
      const unitNumber = lease.unit_number ||
        (lease.units && !Array.isArray(lease.units) ? lease.units.unit_number : null) ||
        (Array.isArray(lease.units) ? lease.units[0]?.unit_number : null) || '';
      const unitId = lease.unit_id;
      const area = safeFloat(lease.area_leased || (lease.units && !Array.isArray(lease.units) ? lease.units.chargeable_area : null) || 0);

      // Resolve brand/tenant name using central utility
      const brandName = resolveBrandName({
        ...lease,
        unit_number: unitNumber || `Lease #${lease.id}`
      });
      const displayUnit = unitNumber || `#${lease.id}`;
      const currentRent = parseFloat(lease.monthly_rent) || 0;

      if (leaseEscalations.length > 0) {
        // Find the next upcoming escalation (effective_from > today)
        const upcomingEsc = leaseEscalations
          .filter(e => e.effective_from && new Date(e.effective_from) > now)
          .sort((a, b) => new Date(a.effective_from) - new Date(b.effective_from))[0];

        if (upcomingEsc) {
          const escDate = new Date(upcomingEsc.effective_from);
          const daysDiff = Math.ceil((escDate - now) / (1000 * 60 * 60 * 24));

          // Calculate new rent based on increase type
          let newRent = currentRent;
          if (upcomingEsc.increase_type === 'Percentage' && upcomingEsc.value) {
            newRent = currentRent * (1 + parseFloat(upcomingEsc.value) / 100);
          } else if (upcomingEsc.increase_type === 'Fixed' && upcomingEsc.value) {
            newRent = currentRent + parseFloat(upcomingEsc.value);
          } else if (upcomingEsc.rate_per_sqft) {
            const area = parseFloat(lease.area_leased || lease.units?.chargeable_area || 0);
            newRent = parseFloat(upcomingEsc.rate_per_sqft) * area;
          }

          if (daysDiff > 0) {
            escalations.push({
              leaseId: lease.id,
              unitId,
              unitNumber: displayUnit,
              brandName,
              area,
              currentRent,
              newRent,
              days: daysDiff,
              escalationDate: escDate,
              increaseType: upcomingEsc.increase_type,
              increaseValue: upcomingEsc.value
            });
          }
        }
      }
    });

    escalations.sort((a, b) => a.days - b.days);
    return escalations;
  }, [leases]);


  // Use centralized formatRent from formatters.js

  return (
    <div className="echo-card" style={{ border: 'none' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', marginBottom: '2px' }}>Upcoming Escalations</h3>
      <p style={{ fontSize: '12px', color: '#64748b', marginBottom: '16px' }}>Rent escalation status · Sorted by urgency</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>Loading...</div>
      ) : escalationData.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>No upcoming escalations found</div>
      ) : (
        <>
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            gap: '16px',
            maxHeight: '300px',
            overflowY: 'auto',
            paddingRight: '8px'
          }}>
            <style>
              {`
                .escalation-scroll::-webkit-scrollbar {
                  width: 6px;
                }
                .escalation-scroll::-webkit-scrollbar-track {
                  background: #f1f5f9;
                  border-radius: 3px;
                }
                .escalation-scroll::-webkit-scrollbar-thumb {
                  background: #cbd5e1;
                  border-radius: 3px;
                }
                .escalation-scroll::-webkit-scrollbar-thumb:hover {
                  background: #94a3b8;
                }
              `}
            </style>
            {escalationData.slice(0, 3).map((esc, i) => {
              const colorInfo = getEscalationColor(esc.days);
              return (
                <div
                  key={i}
                  onClick={() => handleUnitClick(esc.unitId) || handleLeaseClick(esc.leaseId)}
                  style={{
                    display: 'flex',
                    alignItems: 'flex-start',
                    gap: '12px',
                    cursor: 'pointer',
                    padding: '8px',
                    borderRadius: '6px',
                    transition: 'background-color 0.2s'
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f8fafc'}
                  onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'transparent'}
                >
                  <span style={{ fontSize: '14px', fontWeight: 700, color: '#2e66ff', minWidth: '60px' }}>{esc.unitNumber}</span>
                  <div style={{ flex: 1 }}>
                    <p style={{ fontSize: '14px', color: '#0f172a', margin: 0, fontWeight: 500 }}>{esc.brandName}</p>
                    <p style={{ fontSize: '12px', color: '#64748b', margin: 0 }}> {formatRent(safeFloat(esc.currentRent))} <span style={{ color: '#0ea5e9' }}>to</span>  {formatRent(safeFloat(esc.newRent))}</p>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
                    <span style={{ fontSize: '14px', fontWeight: 500, color: colorInfo.text }}>{esc.days} days</span>
                    <span style={{
                      fontSize: '12px',
                      padding: '2px 8px',
                      borderRadius: '9999px',
                      fontWeight: 500,
                      backgroundColor: colorInfo.bg,
                      color: colorInfo.text
                    }}>{colorInfo.status}</span>
                  </div>
                </div>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
};

export default UpcomingEscalations;
